form:Form.form:Scripts:
		function Ejecutar()
{               
 	var diff = (Ctrl('f_hasta').TypedValue() - Ctrl('f_desde').TypedValue()) / 86400000;

	if (diff > 30)
	{
		alert("El reporte soporta hasta 1 mes como rango de fechas máximo.");
 		return false;
	}


	if (Ctrl("list2").TotalRowsCount()==0)
 	{             
 		alert("No hay legajos filtrados.");
 		return false;
 	}

 	if (Ctrl("list2").TotalRowsCount()>40)
 	{             
 		alert("El reporte soporta hasta 40 legajos simultáneos.");
 		return false;
 	}

 	Ctrl('legajos').DelAllRow();
 	for (key in arrB) Ctrl('legajos').AddRow().SetAttr('id', key.substr(1));

	Ctrl("main").DoEvent("FILTER");
}
